fn install_base_x2d_grants(interp: &mut Interp) {
    interp.register_native("base-grants", 0, aot_base_x2d_grants);
    interp.register_aot_direct("base-grants", aot_base_x2d_grants);
}

/// Register every AOT-compiled function on `interp`. Call after kernel
/// boot so these names override the tree-walked defuns.
pub fn install(interp: &mut Interp) {
    install_parents_x2d_of(interp);
    install_reaches(interp);
    install_reaches_x2d_list(interp);
    install_s_x2d_covers(interp);
    install_s_x2d_inter(interp);
    install_classify(interp);
    install_classify_x2d_pair(interp);
    install_classify_x2d_row(interp);
    install_classify_x2d_all(interp);
    install_appnd(interp);
    install_mem(interp);
    install_parents_x2d_h(interp);
    install_parents(interp);
    install_anc_x2d_list(interp);
    install_ancestors(interp);
    install_gfilter(interp);
    install_grants_x2d_of(interp);
    install_expand_x2d_roles(interp);
    install_expand_x2d_all(interp);
    install_bench_x2d_edges(interp);
    install_bench_x2d_forbids(interp);
    install_bench_x2d_permits(interp);
    install_role_x2d_parents(interp);
    install_all_x2d_roles(interp);
    install_base_x2d_grants(interp);
}
